+                        return Ok(Self::scalar(f64::NAN, self.dtype));
+                    }
+                    if v < min {
+                        min = v;
+                    }
+                    if v > max {
+                        max = v;
+                    }
+                }
                 Ok(Self::scalar(max - min, self.dtype))
